console.log("This website is made using the Simpl framework. Read more about Simpl here: https://www.github.com/IJuanTM/Simpl/");const hamburger=document.querySelector("button.hamburger");function toggleMenu(){document.querySelector("nav.menu").classList.toggle("extended"),hamburger.classList.toggle("is-active")}document.querySelectorAll("a.nav-link").forEach((o=>o.onclick=toggleMenu)),hamburger.onclick=toggleMenu;const toTop=document.querySelector("div.to-top");toTop.onclick=()=>{window.scrollTo({top:0,behavior:"smooth"})},window.onscroll=()=>{window.scrollY>256?toTop.classList.remove("invisible"):toTop.classList.add("invisible")},document.querySelector("div.print").onclick=()=>window.print();